			GSD.mats,         
			macro_xs_vector, 
			in.grid_type,    
			in.hash_bins,    
			GSD.max_num_nucs  
			);

	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; j < 5; j++ )
	{
		if( macro_xs_vector[j] > max )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}

	if (i == 0) *GSD.verification = 0;
	*GSD.verification += (max_idx+1);
