unsigned long long run_event_based_simulation_optimization_1(Inputs in, SimulationData GSD, int mype)
{
	char * optimization_name = "Optimization 1 - Kernel splitting + full material & energy sort";

	if( mype == 0)	printf("Simulation Kernel:\"%s\"\n", optimization_name);

	if( mype == 0)	printf("Allocating additional data required by optimized kernel...\n");

	size_t sz;
	size_t total_sz = 0;

	sz = in.lookups * sizeof(double);
	double * d_p_energy_samples;
	gpuErrchk(cudaMalloc(&d_p_energy_samples, sz));
	total_sz += sz;

	sz = in.lookups * sizeof(int);
	int * d_mat_samples;
	gpuErrchk(cudaMalloc(&d_mat_samples, sz));
	total_sz += sz;

	if( mype == 0)	printf("Allocated an additional %.0lf MB of data on GPU.\n", total_sz/1024.0/1024.0);

	int threads = 256;
	int blocks = (in.lookups + threads - 1) / threads;

	sampling_kernel<<<blocks, threads>>>(in, GSD);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());

	if(mype == 0) printf("finished sampling...\n");

	double start, stop;
	start = get_time();

	gpuErrchk(cudaMemcpy(GSD.p_energy_samples, d_p_energy_samples, in.lookups * sizeof(double), cudaMemcpyDeviceToHost));
	gpuErrchk(cudaMemcpy(GSD.mat_samples, d_mat_samples, in.lookups * sizeof(int), cudaMemcpyDeviceToHost));

	quickSort_parallel_i_d(GSD.mat_samples, GSD.p_energy_samples, in.lookups, 1);

	stop = get_time();
	if(mype == 0) printf("Material sort took %.3lf seconds\n", stop-start);

	start = get_time();

	int num_samples_per_mat[12] = {0};
	for( int l = 0; l < in.lookups; l++ )
		num_samples_per_mat[ GSD.mat_samples[l] ]++;

	int offsets[12] = {0};
	for( int m = 1; m < 12; m++ )
		offsets[m] = offsets[m-1] + num_samples_per_mat[m-1];

	stop = get_time();
	if(mype == 0) printf("Counting samples and offsets took %.3lf seconds\n", stop-start);
	start = stop;

	int offset = 0;
	for( int m = 0; m < 12; m++ )
		quickSort_parallel_d_i(GSD.p_energy_samples + offsets[m], GSD.mat_samples + offsets[m], num_samples_per_mat[m], 1);

	stop = get_time();
	if(mype == 0) printf("Energy Sorts took %.3lf seconds\n", stop-start);

	start = get_time();

	gpuErrchk(cudaMemcpy(d_p_energy_samples, GSD.p_energy_samples, in.lookups * sizeof(double), cudaMemcpyHostToDevice));
	gpuErrchk(cudaMemcpy(d_mat_samples, GSD.mat_samples, in.lookups * sizeof(int), cudaMemcpyHostToDevice));

	SimulationData sorted_GSD = GSD;
	sorted_GSD.p_energy_samples = d_p_energy_samples;
	sorted_GSD.mat_samples = d_mat_samples;

	xs_lookup_kernel_optimization_1<<<blocks, threads>>>(in, sorted_GSD);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());

	stop = get_time();
	if(mype == 0) printf("XS Lookups took %.3lf seconds\n", stop-start);

	unsigned long long verification = 0;
	gpuErrchk(cudaMemcpy(&verification, sorted_GSD.verification, sizeof(unsigned long long), cudaMemcpyDeviceToHost));

	gpuErrchk(cudaFree(d_p_energy_samples));
	gpuErrchk(cudaFree(d_mat_samples));

	return verification;
}

