		xs_lookup_kernel_optimization_5<<<blocks, threads>>>(in, GSD, count, offset);
		gpuErrchk(cudaPeekAtLastError());
		gpuErrchk(cudaDeviceSynchronize());

		offset += count;
	}

	unsigned long long verification = 0;
	cudaMemcpy(&verification, GSD.verification, sizeof(unsigned long long), cudaMemcpyDeviceToHost);

	return verification;
}

unsigned long long run_event_based_simulation_optimization_6(Inputs in, SimulationData GSD, int mype)
{
	if( mype == 0)	printf("Running Optimization 6 (Same as 5 for this translation)...\n");
	return run_event_based_simulation_optimization_5(in, GSD, mype);
}

