	gpuErrchk(cudaMalloc(&GSD.mats, SD.length_mats * sizeof(int)));
	gpuErrchk(cudaMemcpy(GSD.mats, SD.mats, SD.length_mats * sizeof(int), cudaMemcpyHostToDevice));
	GSD.length_mats = SD.length_mats;

	gpuErrchk(cudaMalloc(&GSD.nuclide_grid, SD.length_nuclide_grid * sizeof(NuclideGridPoint)));
	gpuErrchk(cudaMemcpy(GSD.nuclide_grid, SD.nuclide_grid, SD.length_nuclide_grid * sizeof(NuclideGridPoint), cudaMemcpyHostToDevice));
	GSD.length_nuclide_grid = SD.length_nuclide_grid;

	if( in.grid_type == UNIONIZED || in.grid_type == HASH )
	{
		gpuErrchk(cudaMalloc(&GSD.index_grid, SD.length_index_grid * sizeof(int)));
		gpuErrchk(cudaMemcpy(GSD.index_grid, SD.index_grid, SD.length_index_grid * sizeof(int), cudaMemcpyHostToDevice));
		GSD.length_index_grid = SD.length_index_grid;
	}
	else
	{
		GSD.index_grid = NULL;
		GSD.length_index_grid = 0;
	}

	if( in.grid_type == UNIONIZED )
	{
		gpuErrchk(cudaMalloc(&GSD.unionized_energy_array, SD.length_unionized_energy_array * sizeof(double)));
		gpuErrchk(cudaMemcpy(GSD.unionized_energy_array, SD.unionized_energy_array, SD.length_unionized_energy_array * sizeof(double), cudaMemcpyHostToDevice));
		GSD.length_unionized_energy_array = SD.length_unionized_energy_array;
	}
	else
	{
		GSD.unionized_energy_array = NULL;
		GSD.length_unionized_energy_array = 0;
	}

	GSD.max_num_nucs = SD.max_num_nucs;

	GSD.p_energy_samples = NULL;
	GSD.length_p_energy_samples = 0;
	GSD.mat_samples = NULL;
	GSD.length_mat_samples = 0;

	return GSD;
}

void release_device_memory(SimulationData GSD)
{
	cudaFree(GSD.num_nucs);
	cudaFree(GSD.concs);
	cudaFree(GSD.mats);
	cudaFree(GSD.nuclide_grid);
	if(GSD.index_grid) cudaFree(GSD.index_grid);
	if(GSD.unionized_energy_array) cudaFree(GSD.unionized_energy_array);
	if(GSD.p_energy_samples) free(GSD.p_energy_samples);
	if(GSD.mat_samples) free(GSD.mat_samples);
}

